import { expect } from 'chai';
import * as path from 'path';
let findRoot = require('find-root');

import Singleton from '../main';

describe('All', () => {

    it('loadLib', () => {
        let root = findRoot(module.filename);
        let packageStr = path.join(root, 'package.json');
        let p = require(packageStr);
        let appEntry = path.join(root, p.main);
        let lib = require(appEntry);
        expect(lib.Version).to.exist;
    });

    it('readVersion', () => {
        let version = Singleton.readVersion(module);
        expect(typeof version.name).to.equal('string');
        expect(typeof version.semver.major).to.equal('number');
        expect(typeof version.semver.minor).to.equal('number');
        expect(typeof version.semver.patch).to.equal('number');
    });

    it('getOrCreateSingleton', () => {
        let singleton1 = Singleton.getOrCreateSingleton(module, () => {
            return {a: 'bla1'};
        });
        let singleton2 = Singleton.getOrCreateSingleton(module, () => {
            return {a: 'bla2'};
        });
        expect(singleton2.__singletonVersion).to.exist;
        expect(singleton1.a).to.equal('bla1');
        expect(singleton2.a).to.equal('bla1');
        expect(singleton1).to.equal(singleton2);
    });
});
